package com.evolua.content.application; import com.evolua.content.domain.Trail; import com.evolua.content.domain.TrailRepository; import java.time.Instant; import java.util.List; import org.springframework.stereotype.Service; @Service public class TrailService { private final TrailRepository repository; public TrailService(TrailRepository repository) { this.repository = repository; } public Trail create(String userId, String title, String description, String category, Boolean premium) { return repository.save(new Trail(null, userId, title, description, category, premium, Instant.now())); } public List<Trail> list(String userId) { return repository.findAllByUserId(userId); } }
